    keySongs: [
      { title: "A Case of You", note: "A love song that is also a farewell — she can drink him like a man drains a country." },
      { title: "River", note: "A Christmas song that has nothing to do with joy — it's about wanting to escape a relationship and her own choices." },
      { title: "California", note: "The counterpoint to idealism: she's been traveling, she's disillusioned, she just wants to go home." },
      { title: "The Last Time I Saw Richard", note: "A conversation in a bar becomes a meditation on whether cynics are just disappointed romantics." }
    ],

    tracklist: [
        { title: "All I Want", displayTitle: "All I Want", duration: "3:32", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "The opening track establishes the album's emotional transparency immediately — Mitchell wants everything and nothing at once, and the dulcimer and guitar arrangement keeps the sound as open as the lyric." },
        { title: "My Old Man", displayTitle: "My Old Man", duration: "3:33", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "A quietly revolutionary love song that refuses to romanticize domesticity while still expressing genuine feeling for her partner — notable for its piano-and-voice intimacy." },
        { title: "Little Green", displayTitle: "Little Green", duration: "3:27", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "A song Mitchell wrote about the daughter she gave up for adoption — a secret she kept publicly for decades — making it one of the most emotionally layered and painful songs on the record." },
        { title: "Carey", displayTitle: "Carey", duration: "3:00", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "The album's most upbeat and playful song, written about a flame-haired cook Mitchell met in a Matala cave in Crete; released as a promotional single, it offers a rare moment of uncomplicated joy amid the album's introspection." },
        { title: "Blue", displayTitle: "Blue", duration: "2:31", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "The spare title track — just Mitchell on piano — is one of the most emotionally direct songs in the singer-songwriter canon, using the color blue to carry an entire emotional argument." },
        { title: "California", displayTitle: "California", duration: "3:53", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "A promotional single that balances disillusionment with longing — Mitchell is traveling Europe but just wants to go home, and the song captures the complicated feeling of nostalgia for a place that isn't perfect." },
        { title: "This Flight Tonight", displayTitle: "This Flight Tonight", duration: "2:50", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "A tense, regret-filled song written on an actual overnight flight, later famously covered by Nazareth in a hard-rock version — a reminder that great songs survive radical reimaginings." },
        { title: "River", displayTitle: "River", duration: "4:00", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "One of the most beloved songs on the album, 'River' is a Christmas song with no joy — Mitchell opens by quoting 'Jingle Bells' on piano and then writes about wanting to skate away from her own failures and heartbreak." },
        { title: "A Case of You", displayTitle: "A Case of You", duration: "4:19", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "Widely considered one of the greatest love songs ever written, this track about a complicated, consuming love — performed on the Appalachian dulcimer — has been covered by hundreds of artists and is the emotional peak of the album." },
        { title: "The Last Time I Saw Richard", displayTitle: "The Last Time I Saw Richard", duration: "4:14", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "The album closes with a conversation in a bar between Mitchell and a cynical ex-boyfriend, asking whether cynics are just disappointed romantics — a quietly devastating ending to one of the most emotionally honest albums ever made." }
      ],

