        { title: "The Boy with the Thorn in His Side", displayTitle: "The Boy with the Thorn in His Side", duration: "3:17", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "Originally released as a standalone single in 1985 before appearing on the album, it became one of the Smiths' most beloved and accessible songs — a plea to be believed in, delivered over one of Marr's most melodically generous arrangements." },
        { title: "Vicar in a Tutu", displayTitle: "Vicar in a Tutu", duration: "2:22", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" },
        { title: "There Is a Light That Never Goes Out", displayTitle: "There Is a Light That Never Goes Out", duration: "4:03", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "Frequently voted the greatest Smiths song ever recorded, its lyric about wanting to die alongside someone in a car crash is delivered as pure romantic euphoria — a song that sounds like joy and reads like despair, and somehow is both at once." },
        { title: "Some Girls Are Bigger Than Others", displayTitle: "Some Girls Are Bigger Than Others", duration: "3:14", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "The album's enigmatic closer, built on one of Marr's most graceful guitar figures and lyrics so abstract as to be nearly meaningless — a deliberate act of deflation after the emotional heights that preceded it." }
