    keyFacts: [
      "Drummer Steven Drozd was struggling with heroin addiction during recording — Wayne Coyne wrote the album partly in response to watching someone disappear.",
      "Made by three people in Oklahoma City with producer Dave Fridmann at Tarbox Road Studios in western New York.",
      "Coyne pitches his voice up slightly throughout — he didn't want the album to sound like him specifically, but like a child asking questions about the universe.",
      "Pitchfork named it album of the decade for the 1990s in 2009."
    ],

    keySongs: [
      { title: "Race for the Prize", note: "Two scientists racing to cure a disease, knowing the cure will kill them. An epic about altruism told in four minutes with a synthesizer orchestra." },
      { title: "The Spark That Bled", note: "Nearly seven minutes — the album's emotional center. A man discovers he has the power to affect others and is terrified by it." },
      { title: "Waitin' for a Superman", note: "A question rather than a statement: is it too late to save anything? The answer the album gives is: probably, but we try anyway." },
      { title: "Feeling Yourself Disintegrate", note: "The most direct meditation on mortality on the record. Coyne wrote it while watching his father die." }
    ],

    tracklist: [
        { title: "Race for the Prize", displayTitle: "Race for the Prize", duration: "4:15", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "The album's lead single introduces its central theme of heroic sacrifice, with Wayne Coyne's lyric about two scientists racing to find a cure delivering genuine emotional weight over an orchestral wall of sound." },
        { title: "A Spoonful Weighs a Ton", displayTitle: "A Spoonful Weighs a Ton", duration: "3:13", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "A sweeping, hymn-like piece that establishes the album's tone of fragile optimism, using layered vocals and dynamics that move from quiet vulnerability to a triumphant climax." },
        { title: "The Spark That Bled", displayTitle: "The Spark That Bled", duration: "6:49", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "One of the album's centrepieces, this seven-minute track was inspired by a moment when drummer Steven Drozd accidentally electrocuted himself in the studio, giving the cosmic lyrics a grounded, personal origin." },
        { title: "The Spiderbite Song", displayTitle: "Slow Motion", duration: "4:04", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" },
        { title: "Buggin'", displayTitle: "What Is the Light?", duration: "1:10", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "Built around a sample from a Neu! record, this track melds krautrock rhythm with the album's orchestral pop sound, and its philosophical questioning title sets up the spiritual arc of side two." },
        { title: "What Is the Light?", displayTitle: "The Observer", duration: "4:26", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" },
        { title: "The Observer", displayTitle: "Waitin' for a Superman", duration: "3:02", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "One of the band's most beloved songs, its simple question — 'Is it gettin' heavy? Well, I thought it was already as heavy as can be' — captures the album's meditation on human limits and the desire for rescue." },
        { title: "Waitin' for a Superman", displayTitle: "Suddenly Everything Has Changed", duration: "4:42", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "A quiet, introspective track that deals directly with the fear of death, written during a period when Coyne was watching his father's health decline." },
        { title: "Suddenly Everything Has Changed", displayTitle: "The Gash", duration: "3:28", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "A rousing, energetic surge that functions as the album's emotional turning point, with Coyne urging perseverance against despair in some of his most direct and affecting lyrics." },
        { title: "The Gash", displayTitle: "Feeling Yourself Disintegrate", duration: "4:36", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "A meditation on mortality and the passage of time, this single is one of the Flaming Lips' most achingly beautiful recordings, with a simple piano-and-vocal core surrounded by shimmering production." },
        { title: "Feeling Yourself Disintegrate", displayTitle: "Sleeping on the Roof", duration: "5:39", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "An ambient instrumental interlude that provides a quiet breathing space before the album's two closing remixes." },
        { title: "Sleeping on the Roof", displayTitle: "Race for the Prize (Remix)", duration: "3:32", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" }
      ],

