        { title: "Exodus", displayTitle: "Exodus", duration: "7:40", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "The album's anthem and title track, named after the biblical departure from Egypt as a metaphor for African diaspora liberation; it reached UK #14 and became an enduring symbol of Rastafari philosophy." },
        { title: "Jamming", displayTitle: "Jamming", duration: "3:31", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "Released as a double A-side with 'Punky Reggae Party,' this joyful track reached UK #9 and exemplifies the celebratory, dance-floor side of Marley's catalogue." },
        { title: "Waiting in Vain", displayTitle: "Waiting in Vain", duration: "4:16", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "A tender love song that reached UK #27, showcasing Marley's gift for blending intimate romance with the smooth, melodic side of roots reggae." },
        { title: "Turn Your Lights Down Low", displayTitle: "Turn Your Lights Down Low", duration: "3:39", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" },
        { title: "Three Little Birds", displayTitle: "Three Little Birds", duration: "3:00", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "One of Marley's most beloved songs, its message of reassurance ('Don't worry about a thing') has made it a global standard for comfort and optimism." },
        { title: "One Love / People Get Ready", displayTitle: "One Love/People Get Ready", duration: "2:51", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "Marley's medley with Curtis Mayfield's 1965 classic reached UK #5 and has since become one of the most internationally recognized anthems of unity and peace." }
