      "classroomSafeMode": true,
      "keyFacts": [
          "Songs in the Key of Life is a double album plus a bonus 4-song EP — 21 tracks total on the vinyl release.",
          "Stevie Wonder played the majority of instruments himself, including piano, Fender Rhodes, clavinet, drums, harmonica, and multiple synthesizers.",
          "The album spent 14 weeks at #1 on the Billboard 200 and topped charts worldwide.",
          "It was dedicated partly to Duke Ellington, who died in 1974 — 'Sir Duke' is an explicit tribute to him.",
          "Zeth Lundy wrote a celebrated 33⅓ book analyzing the album's construction, themes, and cultural legacy.",
          "Paul McCartney reportedly told Wonder, 'You'll never top this one, Stevie' — a high-pressure compliment Wonder later recalled with humor."
      ],
      "keySongs": [
          {
              "title": "Sir Duke",
              "note": "A joyful tribute to Duke Ellington and the jazz greats — one of the most infectious horn riffs in pop history."
          },
          {
              "title": "Isn't She Lovely",
              "note": "Written for his newborn daughter Aisha — pure, uncomplicated joy in song form, with Wonder's harmonica at its most playful."
          },
          {
              "title": "As",
              "note": "An eight-minute meditation on unconditional love that builds into one of the most euphoric album closers in soul history."
          },
          {
              "title": "Village Ghetto Land",
              "note": "A baroque strings arrangement wrapped around a devastating critique of poverty and neglect — the album's sharpest political moment."
          },
          {
              "title": "I Wish",
              "note": "A funk-driven nostalgia trip about childhood that became one of the defining groove records of the era."
          }
      ],
      "tracklist": [
        { title: "Love's in Need of Love Today", displayTitle: "Love's in Need of Love Today", duration: "7:05", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "The album's opening hymn establishes its sweeping ambition immediately: an eight-minute orchestral gospel invocation that frames the entire project as a meditation on humanity's capacity for love." },
        { title: "Have a Talk with God", displayTitle: "Have a Talk with God", duration: "2:42", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" },
        { title: "Village Ghetto Land", displayTitle: "Village Ghetto Land", duration: "3:25", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "Wonder narrates urban poverty over a deliberately ironic string quartet arrangement — the baroque elegance of the music sharply contradicting the deprivation described in the lyrics." },
        { title: "Contusion", displayTitle: "Contusion", duration: "3:46", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "A jazz-fusion instrumental that demonstrates Wonder's command of multiple instruments and won the 1977 Grammy for Best Rhythm and Blues Instrumental Performance." },
        { title: "Sir Duke", displayTitle: "Sir Duke", duration: "3:52", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "A US #1 tribute to Duke Ellington and other jazz giants (Basie, Glenn Miller, Louis Armstrong, Ella Fitzgerald), this track made jazz history accessible to a new generation of pop listeners." },
        { title: "I Wish", displayTitle: "I Wish", duration: "4:11", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "The album's first US #1 single features one of the most distinctive bass lines in pop history (played by Nathan Watts) and established the template for '70s-nostalgic funk that artists still sample today." },
        { title: "Knocks Me Off My Feet", displayTitle: "Knocks Me Off My Feet", duration: "4:00", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" },
        { title: "Pastime Paradise", displayTitle: "Pastime Paradise", duration: "3:27", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "This track's choral arrangement and social critique of nostalgia gained a massive new audience when Coolio sampled it for 'Gangsta's Paradise' in 1995, one of the most successful samples in hip-hop history." },
        { title: "Summer Soft", displayTitle: "Summer Soft", duration: "3:18", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" },
        { title: "Ordinary Pain", displayTitle: "Ordinary Pain", duration: "7:10", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "A two-part song where Wonder sings the male perspective and Shirley Brewer answers with the female perspective, an early example of Wonder's interest in dialogue and duality within a single track." },
        { title: "Isn't She Lovely", displayTitle: "Isn't She Lovely", duration: "6:34", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "Written for his newborn daughter Aisha, this song was never released as a US single — Motown felt it was too long — yet became one of Wonder's most beloved recordings through radio play alone." },
        { title: "Joy Inside My Tears", displayTitle: "Joy Inside My Tears", duration: "6:30", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" },
        { title: "Black Man", displayTitle: "Black Man", duration: "8:28", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "This nearly nine-minute track celebrates multiracial contributions to American history through a call-and-response structure, functioning almost as an educational exercise in reclaiming erased histories." },
        { title: "Ngiculela – Es Una Historia / I Am Singing", displayTitle: "Ngiculela — Es Una Historia — I Am Singing", duration: "3:48", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "Wonder sings the same melody in Zulu, Spanish, and English, making a statement about the universality of song that transcends language and geography." },
        { title: "If It's Magic", displayTitle: "If It's Magic", duration: "3:12", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "One of the album's most intimate tracks, featuring only Wonder's voice and Dorothy Ashby's harp — a fragile, uncommonly beautiful pairing." },
        { title: "As", displayTitle: "As", duration: "7:08", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "A seven-minute devotional anthem built on an unusual extended metaphor of cosmic impossibilities, 'As' has become one of Wonder's most celebrated compositions and a staple of wedding ceremonies worldwide." },
        { title: "Another Star", displayTitle: "Another Star", duration: "8:28", single: true, explicit: false, hiddenFromStudentView: false, teacherNote: "Reaching US #32, this Latin-flavored dance track featuring Hector Maseda on congas showcases Wonder's embrace of Afro-Latin rhythms and serves as the double album's most jubilant closing statement." },
        { title: "Saturn", displayTitle: "Saturn", duration: "4:54", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "Wonder's Afrofuturist fantasy of a peaceful planet free from racism made this EP track a touchstone for later Afrofuturism in music and art." },
        { title: "Ebony Eyes", displayTitle: "Ebony Eyes", duration: "4:00", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" },
        { title: "All Day Sucker", displayTitle: "All Day Sucker", duration: "5:02", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" },
        { title: "Easy Goin' Evening (My Mama's Call)", displayTitle: "Easy Goin' Evening (My Mama's Call)", duration: "3:39", single: false, explicit: false, hiddenFromStudentView: false, teacherNote: "" }
      ],
