      "keySongs": [
          {
              "title": "The Big Ship",
              "note": "No melody, no lyrics, no rhythm to speak of — just slow synthesizer chords that somehow feel enormous. Does it affect you emotionally? If it does, what does that tell you about what music actually needs to work?"
          },
          {
              "title": "St. Elmo's Fire",
              "note": "The most song-like track on the album. Compare it to the purely textural tracks — does the contrast make the songs feel more or less powerful?"
          },
          {
              "title": "Becalmed",
              "note": "The title means a ship with no wind — completely still. Listen to how Eno creates stillness as a musical texture, not just an absence of sound."
          },
          {
              "title": "Over Fire Island",
              "note": "One minute forty-eight seconds of pure ambient texture. No song. Try to listen without waiting for something to happen. What do you notice?"
          }
      ],
