    "keySongs": [
        {
            "title": "Born in the U.S.A.",
            "note": "Listen to the lyrics word for word while the music plays. Write down what the song is actually about — then compare that to what the title and sound suggest."
        },
        {
            "title": "I'm on Fire",
            "note": "Notice how different this sounds from the title track. Same album, same artist — but this is quiet, minimal, and intimate. What does that range tell you about Springsteen as a songwriter?"
        },
        {
            "title": "Dancing in the Dark",
            "note": "This was written to order when the label demanded a radio hit. Does knowing that change how you hear it? Can a calculated song still be great?"
        },
        {
            "title": "My Hometown",
            "note": "The album ends here: a father showing his son a town that's been left behind. How does ending on this track change how you understand everything that came before it?"
        }
    ],
