    "keySongs": [
        {
            "title": "Waltz #2 (XO)",
            "note": "Smith's most celebrated song — a waltz-time conversation with his mother, arranged with strings and layered harmonies. The melody sounds almost cheerful; the lyric is not. Listen for the gap between how it sounds and what it is saying."
        },
        {
            "title": "Baby Britain",
            "note": "The album's most Beatles-influenced track — a driving guitar pop song that demonstrates how Smith absorbed that influence without copying it. Listen for the production details: the harmonies, the bass line, the drum sound."
        },
        {
            "title": "Sweet Adeline",
            "note": "The album opens with a cappella harmonies — Smith's voice layered over itself, no instruments. It announces that this is an album about voice and intimacy, however lush it gets."
        },
        {
            "title": "Pitseleh",
            "note": "One of the album's most quietly devastating tracks — a sparse guitar ballad that doesn't need orchestration. Listen to what he does with just voice and guitar when the rest of the album has been so full."
        }
    ],
