    "keySongs": [
        {
            "title": "The Magnificent Seven",
            "note": "One of the earliest rap-influenced tracks by a major rock band — Strummer free-associates lyrics over funk in real time, two years before Grandmaster Flash's 'The Message.'"
        },
        {
            "title": "Washington Bullets",
            "note": "Strummer names specific U.S. foreign interventions — Nicaragua, Chile, Afghanistan — directly. Political songwriting as explicit as it gets."
        },
        {
            "title": "The Sound of Sinners",
            "note": "The Clash in a gospel context — unexpected, genuine, and strangely moving. The album's range means that after thirty minutes of politics and dub, you get a choir."
        },
        {
            "title": "Career Opportunities",
            "note": "The children's choir cover of their own early punk song — a joke that somehow becomes a commentary on everything between the original and this version."
        }
    ],
